(function(){
  // Local loader that ensures XLSX is available. This keeps a local file present while
  // still fetching the real library from the CDN if needed. If you prefer, replace
  // this file with the full xlsx.full.min.js bundle to avoid the CDN entirely.
  if (window.XLSX) return;
  try {
    var s = document.createElement('script');
    s.src = 'https://cdn.jsdelivr.net/npm/xlsx@0.18.5/dist/xlsx.full.min.js';
    s.async = false; // keep execution order
    s.onload = function(){
      try { console.log('XLSX loaded (via local proxy).');
        var badge = document.getElementById('xlsxBadge');
        if (badge) { badge.textContent = 'XLSX ready'; badge.classList.remove('locked'); badge.classList.add('unlocked'); }
      } catch(e){}
    };
    s.onerror = function(){ console.warn('Failed to load XLSX from CDN via local proxy.'); };
    (document.head || document.documentElement).appendChild(s);
  } catch (e) {
    console.error('Failed to load XLSX proxy', e);
  }
})();
